/**
 * station-uds.test.ts — verify StationUds Amplituhedron admin path
 * wire shape.
 *
 * The transport requires a live UDS server, so we boot a minimal
 * loopback in-process via `node:net.createServer` that parses the
 * 4-byte length prefix + ASCII headers/body request frame, lets the
 * test inspect the captured request, and replies with a programmable
 * envelope so we can assert hit/miss/error handling end-to-end.
 *
 * Scope: just the Amplituhedron admin path added in Leg 4 Gap A
 * (Phase 2). The legacy forward/embed/lm-head/cobordism methods
 * pre-date this test file and have their own (integration) coverage
 * via fat-station-uds.rs benches.
 */

import { afterAll, beforeAll, describe, expect, it } from 'vitest';
import { createServer, type Server, type Socket } from 'node:net';
import { mkdtempSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import {
  AMPLITUHEDRON_CONTENT_TYPE,
  encodeReplayResponse,
  decodeCaptureRequest,
} from '../src/amplituhedron-wire';
import { StationUds } from '../src/station-uds';

interface CapturedRequest {
  method: string;
  path: string;
  headers: Map<string, string>;
  body: Uint8Array;
}

type ReplyFn = (req: CapturedRequest) => { status: number; body: Uint8Array };

class LoopbackUdsServer {
  private readonly server: Server;
  readonly socketPath: string;
  reply: ReplyFn = () => ({ status: 204, body: new Uint8Array(0) });
  captured: CapturedRequest[] = [];

  constructor() {
    const dir = mkdtempSync(join(tmpdir(), 'station-uds-test-'));
    this.socketPath = join(dir, 's.sock');
    this.server = createServer((sock: Socket) => this.handleConn(sock));
  }

  listen(): Promise<void> {
    return new Promise((resolve, reject) => {
      this.server.once('error', reject);
      this.server.listen(this.socketPath, () => resolve());
    });
  }

  close(): Promise<void> {
    return new Promise((resolve) => {
      this.server.close(() => resolve());
      try {
        rmSync(this.socketPath, { force: true });
      } catch {
        // ignore
      }
    });
  }

  private handleConn(sock: Socket): void {
    const chunks: Uint8Array[] = [];
    let received = 0;
    let totalLen = -1;
    sock.on('data', (chunk: Buffer) => {
      chunks.push(new Uint8Array(chunk));
      received += chunk.length;
      if (totalLen < 0 && received >= 4) {
        const merged = concat(chunks);
        totalLen =
          (merged[0]! << 24) |
          (merged[1]! << 16) |
          (merged[2]! << 8) |
          merged[3]!;
        chunks.length = 0;
        chunks.push(merged.subarray(4));
        received = merged.length - 4;
      }
      if (totalLen >= 0 && received >= totalLen) {
        const merged = concat(chunks).subarray(0, totalLen);
        const req = parseRequest(merged);
        this.captured.push(req);
        const r = this.reply(req);
        sock.write(encodeReply(r.status, r.body));
        sock.end();
      }
    });
    sock.on('error', () => {
      // ignore
    });
  }
}

function concat(parts: Uint8Array[]): Uint8Array {
  const total = parts.reduce((n, p) => n + p.length, 0);
  const out = new Uint8Array(total);
  let off = 0;
  for (const p of parts) {
    out.set(p, off);
    off += p.length;
  }
  return out;
}

function parseRequest(buf: Uint8Array): CapturedRequest {
  let split = -1;
  for (let i = 0; i < buf.length - 1; i++) {
    if (buf[i] === 0x0a && buf[i + 1] === 0x0a) {
      split = i;
      break;
    }
  }
  if (split < 0) {
    throw new Error('test server: missing blank-line separator');
  }
  const headerStr = new TextDecoder().decode(buf.subarray(0, split));
  const body = new Uint8Array(buf.subarray(split + 2));
  let method = '';
  let path = '';
  const headers = new Map<string, string>();
  for (const line of headerStr.split('\n')) {
    if (!line) continue;
    const colon = line.indexOf(':');
    if (colon < 0) continue;
    const k = line.slice(0, colon).trim();
    const v = line.slice(colon + 1).trim();
    const lk = k.toLowerCase();
    if (lk === 'method') method = v;
    else if (lk === 'path') path = v;
    else headers.set(lk, v);
  }
  return { method, path, headers, body };
}

function encodeReply(status: number, body: Uint8Array): Uint8Array {
  const headerBlock = `status: ${status}\n\n`;
  const headerBytes = new TextEncoder().encode(headerBlock);
  const total = headerBytes.length + body.length;
  const out = new Uint8Array(4 + total);
  out[0] = (total >>> 24) & 0xff;
  out[1] = (total >>> 16) & 0xff;
  out[2] = (total >>> 8) & 0xff;
  out[3] = total & 0xff;
  out.set(headerBytes, 4);
  out.set(body, 4 + headerBytes.length);
  return out;
}

describe('StationUds amplituhedron admin path', () => {
  let server: LoopbackUdsServer;

  beforeAll(async () => {
    server = new LoopbackUdsServer();
    await server.listen();
  });

  afterAll(async () => {
    await server.close();
  });

  it('POSTs JSON to /amplituhedron/replay and decodes a bitwise hit envelope', async () => {
    server.captured = [];
    const tail = new Float32Array([0.125, 0.25, 0.5]);
    const prefix = new Float32Array([2, 4, 6, 8, 10, 12]);
    server.reply = () => ({
      status: 200,
      body: encodeReplayResponse({
        hit: true,
        tailLen: tail.length,
        kvSlabLen: 0,
        tailResidual: tail,
        prefixResidualLen: prefix.length,
        prefixResidual: prefix,
      }),
    });

    const s = new StationUds({
      socketPath: server.socketPath,
      startLayer: 0,
      endLayer: 8,
      timeoutMs: 2000,
    });
    // Synthetic decimal u64 fixture — codec requires decimal u64 strings.
    const result = await s.amplituhedronReplay({
      prefixHash: '51966',
      prefixLen: 9,
      layerLo: 0,
      layerHi: 8,
      requestId: 'req-uds-amph-1',
    });

    expect(server.captured).toHaveLength(1);
    const r = server.captured[0]!;
    expect(r.method).toBe('POST');
    expect(r.path).toBe('/amplituhedron/replay');
    expect(r.headers.get('content-type')).toBe('application/json');
    expect(r.headers.get('accept')).toBe(AMPLITUHEDRON_CONTENT_TYPE);
    const sent = JSON.parse(new TextDecoder().decode(r.body)) as Record<
      string,
      unknown
    >;
    expect(sent['prefix_hash']).toBe('51966');
    expect(sent['prefix_len']).toBe(9);
    expect(sent['layer_lo']).toBe(0);
    expect(sent['layer_hi']).toBe(8);
    expect(sent['request_id']).toBe('req-uds-amph-1');
    expect(result.hit).toBe(true);
    expect(Array.from(result.tailResidual ?? new Float32Array())).toEqual([
      0.125, 0.25, 0.5,
    ]);
    expect(Array.from(result.prefixResidual ?? new Float32Array())).toEqual([
      2, 4, 6, 8, 10, 12,
    ]);
    expect(result.tailFingerprint).toMatch(/^[0-9a-f]{16}$/);
    expect(result.prefixFingerprint).toMatch(/^[0-9a-f]{16}$/);
  });

  it('treats 204 No Content as a clean miss', async () => {
    server.captured = [];
    server.reply = () => ({ status: 204, body: new Uint8Array(0) });

    const s = new StationUds({
      socketPath: server.socketPath,
      startLayer: 0,
      endLayer: 8,
      timeoutMs: 2000,
    });
    const result = await s.amplituhedronReplay({
      prefixHash: '1111111111',
      prefixLen: 1,
      layerLo: 0,
      layerHi: 8,
    });
    expect(result.hit).toBe(false);
    expect(result.tailResidual).toBeUndefined();
  });

  it('returns hit:false defensively on a 500 — never throws on replay path', async () => {
    server.captured = [];
    server.reply = () => ({
      status: 500,
      body: new TextEncoder().encode('boom'),
    });

    const s = new StationUds({
      socketPath: server.socketPath,
      startLayer: 0,
      endLayer: 8,
      timeoutMs: 2000,
    });
    const result = await s.amplituhedronReplay({
      prefixHash: '9999999999',
      prefixLen: 1,
      layerLo: 0,
      layerHi: 8,
    });
    expect(result.hit).toBe(false);
  });

  it('POSTs bitwise tail_residual to /amplituhedron/capture and resolves void', async () => {
    server.captured = [];
    server.reply = () => ({
      status: 200,
      body: new TextEncoder().encode('{"captured":true}'),
    });

    const s = new StationUds({
      socketPath: server.socketPath,
      startLayer: 0,
      endLayer: 8,
      timeoutMs: 2000,
    });
    await s.amplituhedronCapture({
      prefixHash: '4242424242',
      prefixLen: 22,
      layerLo: 0,
      layerHi: 8,
      tailResidual: new Float32Array([1.5, 2.5, 3.5]),
      requestId: 'req-uds-capture-1',
    });

    expect(server.captured).toHaveLength(1);
    const r = server.captured[0]!;
    expect(r.path).toBe('/amplituhedron/capture');
    expect(r.headers.get('content-type')).toBe(AMPLITUHEDRON_CONTENT_TYPE);
    const decoded = decodeCaptureRequest(r.body);
    expect(decoded.prefixHash).toBe('4242424242');
    expect(decoded.prefixLen).toBe(22);
    expect(decoded.layerLo).toBe(0);
    expect(decoded.layerHi).toBe(8);
    expect(Array.from(decoded.tailResidual ?? new Float32Array())).toEqual([
      1.5, 2.5, 3.5,
    ]);
  });

  it('capture swallows server errors — never throws on best-effort path', async () => {
    server.captured = [];
    server.reply = () => ({
      status: 500,
      body: new TextEncoder().encode('nope'),
    });

    const s = new StationUds({
      socketPath: server.socketPath,
      startLayer: 0,
      endLayer: 8,
      timeoutMs: 2000,
    });
    await expect(
      s.amplituhedronCapture({
        prefixHash: '9999999999',
        prefixLen: 1,
        layerLo: 0,
        layerHi: 8,
      })
    ).resolves.toBeUndefined();
  });

  it('replay sets Accept and capture sets Content-Type to application/x-bitwise-residual', async () => {
    // Replay leg: Accept must announce the bitwise wire.
    server.captured = [];
    server.reply = () => ({ status: 204, body: new Uint8Array(0) });
    const replayStation = new StationUds({
      socketPath: server.socketPath,
      startLayer: 0,
      endLayer: 8,
      timeoutMs: 2000,
    });
    await replayStation.amplituhedronReplay({
      prefixHash: '8888888888',
      prefixLen: 1,
      layerLo: 0,
      layerHi: 8,
    });
    expect(server.captured).toHaveLength(1);
    expect(server.captured[0]!.headers.get('accept')).toBe(
      AMPLITUHEDRON_CONTENT_TYPE
    );

    // Capture leg: Content-Type must declare the bitwise wire.
    server.captured = [];
    server.reply = () => ({
      status: 200,
      body: new TextEncoder().encode('{"captured":true}'),
    });
    const captureStation = new StationUds({
      socketPath: server.socketPath,
      startLayer: 0,
      endLayer: 8,
      timeoutMs: 2000,
    });
    await captureStation.amplituhedronCapture({
      prefixHash: '8888888888',
      prefixLen: 1,
      layerLo: 0,
      layerHi: 8,
      tailResidual: new Float32Array([1, 2]),
    });
    expect(server.captured).toHaveLength(1);
    expect(server.captured[0]!.headers.get('content-type')).toBe(
      AMPLITUHEDRON_CONTENT_TYPE
    );
  });
});
